import React, { useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import { useFileUpload } from '../../hooks/useFileUpload';
import { supabase } from '../../supabaseClient';

interface FileUploadProps {
  documentId: string;
  currentFileUrl?: string | null;
  onFileUploaded: (url: string) => void;
  onFileDeleted?: () => void;
  allowedTypes?: string[];
  maxFileSize?: number; // en octets
}

const FileUpload: React.FC<FileUploadProps> = ({
  documentId,
  currentFileUrl,
  onFileUploaded,
  onFileDeleted,
  allowedTypes = ['image/*', 'application/pdf', 'audio/*', 'video/*'],
  maxFileSize = 50 * 1024 * 1024 // 50 Mo
}) => {
  const { 
    uploadFile, 
    deleteFile, 
    progress, 
    isUploading, 
    error,
    fileUrl,
    reset
  } = useFileUpload();

  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    if (acceptedFiles.length === 0) return;

    const file = acceptedFiles[0];

    // Vérification taille
    if (file.size > maxFileSize) {
      alert(`Le fichier dépasse la taille maximale autorisée (${maxFileSize / 1024 / 1024} Mo)`);
      return;
    }

    // Upload
    const url = await uploadFile(file, documentId, (uploadedUrl) => {
      onFileUploaded(uploadedUrl);
    });

    if (!url) {
      alert('Erreur lors de l\'upload du fichier');
    }
  }, [documentId, uploadFile, onFileUploaded, maxFileSize]);

  // Convertir allowedTypes (string[]) vers le format Accept requis par react-dropzone
const acceptProp = React.useMemo(() => {
  return allowedTypes.reduce((acc, mimeType) => {
    acc[mimeType] = [];
    return acc;
  }, {} as { [key: string]: string[] });
}, [allowedTypes]);

const { getRootProps, getInputProps, isDragActive } = useDropzone({
  onDrop,
  accept: acceptProp, // ✅ Format correct : { 'image/*': [], 'application/pdf': [] }
  multiple: false,
  maxSize: maxFileSize
});

  const handleDelete = async () => {
    if (!currentFileUrl) return;

    const confirm = window.confirm('Êtes-vous sûr de vouloir supprimer ce fichier ?');
    if (!confirm) return;

    const success = await deleteFile(currentFileUrl);
    if (success && onFileDeleted) {
      onFileDeleted();
      reset();
    } else {
      alert('Erreur lors de la suppression du fichier');
    }
  };

  const getFileIcon = (url: string) => {
    if (!url) return '📄';
    
    const lowerUrl = url.toLowerCase();
    if (lowerUrl.endsWith('.pdf')) return '📕';
    if (lowerUrl.match(/\.(jpg|jpeg|png|gif|bmp|webp)$/)) return '🖼️';
    if (lowerUrl.match(/\.(mp3|wav|ogg|aac)$/)) return '🎵';
    if (lowerUrl.match(/\.(mp4|avi|mov|wmv)$/)) return '🎬';
    if (lowerUrl.endsWith('.doc') || lowerUrl.endsWith('.docx')) return '📘';
    if (lowerUrl.endsWith('.txt')) return '📝';
    return '📄';
  };

  const getFileType = (url: string) => {
    if (!url) return 'Fichier';
    
    const lowerUrl = url.toLowerCase();
    if (lowerUrl.endsWith('.pdf')) return 'PDF';
    if (lowerUrl.match(/\.(jpg|jpeg|png|gif|bmp|webp)$/)) return 'Image';
    if (lowerUrl.match(/\.(mp3|wav|ogg|aac)$/)) return 'Audio';
    if (lowerUrl.match(/\.(mp4|avi|mov|wmv)$/)) return 'Vidéo';
    if (lowerUrl.endsWith('.doc') || lowerUrl.endsWith('.docx')) return 'Word';
    if (lowerUrl.endsWith('.txt')) return 'Texte';
    return 'Fichier';
  };

  return (
    <div className="space-y-4">
      {/* Fichier actuel */}
      {currentFileUrl && (
        <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-lg p-4 animate-fade-in">
          <div className="flex items-start justify-between">
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-3 mb-2">
                <span className="text-3xl">{getFileIcon(currentFileUrl)}</span>
                <div className="min-w-0 flex-1">
                  <h4 className="font-medium text-blue-900 dark:text-blue-100 truncate">
                    {decodeURIComponent(currentFileUrl.split('/').pop() || 'Fichier')}
                  </h4>
                  <p className="text-sm text-blue-700 dark:text-blue-300">
                    {getFileType(currentFileUrl)}
                  </p>
                </div>
              </div>
              
              <div className="mt-3 flex items-center gap-2">
                <a
                  href={currentFileUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center px-3 py-1.5 text-sm font-medium text-blue-700 dark:text-blue-300 bg-blue-100 dark:bg-blue-900 rounded-md hover:bg-blue-200 dark:hover:bg-blue-800 transition-colors"
                >
                  <i className="fas fa-eye mr-1.5"></i>
                  Voir
                </a>
                <button
                  onClick={handleDelete}
                  className="inline-flex items-center px-3 py-1.5 text-sm font-medium text-red-700 dark:text-red-300 bg-red-100 dark:bg-red-900 rounded-md hover:bg-red-200 dark:hover:bg-red-800 transition-colors"
                >
                  <i className="fas fa-trash-alt mr-1.5"></i>
                  Supprimer
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Zone de drop */}
      <div
        {...getRootProps()}
        className={`border-2 border-dashed rounded-lg p-8 text-center cursor-pointer transition-all duration-300 transform hover:scale-[1.02]
          ${isDragActive 
            ? 'border-primary bg-primary/5 animate-pulse' 
            : isUploading
              ? 'border-blue-400 bg-blue-50 dark:bg-blue-900/20'
              : 'border-gray-300 dark:border-gray-600 hover:border-primary hover:bg-gray-50 dark:hover:bg-gray-700/50'
          }`}
      >
        <input {...getInputProps()} />
        
        {isUploading ? (
          // État upload en cours
          <div className="space-y-4">
            <div className="flex justify-center">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-primary border-t-transparent rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center text-primary font-bold">
                  {progress}%
                </div>
              </div>
            </div>
            
            <div className="space-y-2">
              <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                Upload en cours...
              </p>
              
              <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2 overflow-hidden">
                <div
                  className="h-full bg-gradient-to-r from-primary to-primary-dark transition-all duration-300"
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
            </div>
          </div>
        ) : error ? (
          // État erreur
          <div className="space-y-3 animate-shake">
            <div className="flex justify-center">
              <div className="w-16 h-16 bg-red-100 dark:bg-red-900 rounded-full flex items-center justify-center">
                <i className="fas fa-exclamation-triangle text-red-600 dark:text-red-400 text-2xl"></i>
              </div>
            </div>
            
            <div className="space-y-2">
              <p className="text-sm font-medium text-red-700 dark:text-red-300">
                {error}
              </p>
              <p className="text-xs text-red-600 dark:text-red-400">
                Cliquez ou glissez un fichier pour réessayer
              </p>
            </div>
          </div>
        ) : (
          // État normal
          <div className="space-y-3">
            <div className="flex justify-center">
              <div className="w-16 h-16 bg-primary/10 dark:bg-primary/20 rounded-full flex items-center justify-center transition-transform duration-300 group-hover:scale-110">
                <i className="fas fa-cloud-upload-alt text-primary text-2xl group-hover:animate-bounce"></i>
              </div>
            </div>
            
            <div className="space-y-1">
              {isDragActive ? (
                <p className="text-lg font-semibold text-primary animate-pulse">
                  Déposez le fichier ici...
                </p>
              ) : (
                <p className="text-lg font-semibold text-gray-900 dark:text-white">
                  Glissez-déposez un fichier ici
                </p>
              )}
              
              <p className="text-sm text-gray-500 dark:text-gray-400">
                ou cliquez pour parcourir
              </p>
            </div>
            
            <div className="text-xs text-gray-400 dark:text-gray-500">
              <p>Formats supportés : PDF, Images, Audio, Vidéo</p>
              <p>Taille maximale : {maxFileSize / 1024 / 1024} Mo</p>
            </div>
          </div>
        )}
      </div>

      {/* Aperçu si fichier image/audio/vidéo */}
      {currentFileUrl && (
        <div className="mt-4">
          {currentFileUrl.toLowerCase().match(/\.(jpg|jpeg|png|gif|bmp|webp)$/) && (
            <div className="relative group">
              <img
                src={currentFileUrl}
                alt="Aperçu"
                className="w-full h-64 object-cover rounded-lg shadow-md transition-transform duration-300 group-hover:scale-105"
              />
              <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-20 transition-opacity duration-300 rounded-lg"></div>
            </div>
          )}
          
          {currentFileUrl.toLowerCase().match(/\.(mp3|wav|ogg|aac)$/) && (
            <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg p-4">
              <audio controls className="w-full">
                <source src={currentFileUrl} />
                Votre navigateur ne supporte pas l'élément audio.
              </audio>
            </div>
          )}
          
          {currentFileUrl.toLowerCase().match(/\.(mp4|avi|mov|wmv)$/) && (
            <div className="bg-gray-50 dark:bg-gray-700/50 rounded-lg overflow-hidden shadow-md">
              <video controls className="w-full">
                <source src={currentFileUrl} />
                Votre navigateur ne supporte pas l'élément vidéo.
              </video>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default FileUpload;
